import { useState } from 'react';
import pic3 from '../pictures/pic3.jpg';
function RegisterPage() {
  const [formData, setFormData] = useState({
    fullname: '', email: '', username: '',
    password: '', confirmPassword: '', dob: '',
    experience: '', terms: false
  });
  const [errors, setErrors] = useState({});

  const update = (field, value) => setFormData(prev => ({ ...prev, [field]: value }));

  const validateForm = (e) => {
    e.preventDefault();
    const errs = {};
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!formData.fullname.trim())
      errs.fullname = "Full name is required.";

    if (!formData.email.trim())
      errs.email = "Email address is required.";
    else if (!emailRegex.test(formData.email))
      errs.email = "Please enter a valid email format.";

    if (!formData.username.trim())
      errs.username = "Username is required.";

    if (formData.password.length < 8)
      errs.password = "Password must be at least 8 characters.";

    if (formData.password !== formData.confirmPassword)
      errs.confirmPassword = "Passwords do not match.";

    if (!formData.dob) {
      errs.dob = "Date of birth is required.";
    } else {
      const birthDate = new Date(formData.dob);
      const today = new Date();
      let age = today.getFullYear() - birthDate.getFullYear();
      const m = today.getMonth() - birthDate.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) age--;
      if (age < 18) errs.dob = "You must be at least 18 years old.";
    }

    if (!formData.experience)
      errs.experience = "Please select your experience level.";

    if (!formData.terms)
      errs.terms = "You must agree to the terms.";

    setErrors(errs);

    if (Object.keys(errs).length === 0) {
      alert("Registration successful! Welcome to the club.");
    }
  };

  return (
    <main>
      <div className="container">
        <h1>Join the Travel Club</h1>
        <img src={pic3} alt="Travel Gear" />

        <form id="registrationForm" onSubmit={validateForm}>

          <label htmlFor="fullname">Full Name:</label>
          <input type="text" id="fullname" placeholder="Enter your full name"
            value={formData.fullname} onChange={e => update('fullname', e.target.value)} />
          {errors.fullname && <span className="error">{errors.fullname}</span>}

          <label htmlFor="email">Email Address:</label>
          <input type="email" id="email" placeholder="example@mail.com"
            value={formData.email} onChange={e => update('email', e.target.value)} />
          {errors.email && <span className="error">{errors.email}</span>}

          <label htmlFor="username">Preferred Username:</label>
          <input type="text" id="username" placeholder="Choose a username"
            value={formData.username} onChange={e => update('username', e.target.value)} />
          {errors.username && <span className="error">{errors.username}</span>}

          <label htmlFor="password">Password:</label>
          <input type="password" id="password" placeholder="Min. 8 characters"
            value={formData.password} onChange={e => update('password', e.target.value)} />
          {errors.password && <span className="error">{errors.password}</span>}

          <label htmlFor="confirmPassword">Confirm Password:</label>
          <input type="password" id="confirmPassword" placeholder="Repeat your password"
            value={formData.confirmPassword} onChange={e => update('confirmPassword', e.target.value)} />
          {errors.confirmPassword && <span className="error">{errors.confirmPassword}</span>}

          <label htmlFor="dob">Date of Birth:</label>
          <input type="date" id="dob"
            value={formData.dob} onChange={e => update('dob', e.target.value)} />
          {errors.dob && <span className="error">{errors.dob}</span>}

          {/* Experience level radio buttons — FIX: name was "type" in HTML but
              querySelector looked for name="level". Unified to "experience" here. */}
          <p><strong>Experience Level:</strong></p>
          {['Beginner', 'Intermediate', 'Expert'].map(level => (
            <label key={level} style={{ display: 'block', marginBottom: '4px' }}>
              <input
                type="radio"
                name="experience"
                value={level}
                style={{ width: 'auto', marginRight: '8px' }}
                checked={formData.experience === level}
                onChange={e => update('experience', e.target.value)}
              />
              {level}
            </label>
          ))}
          {errors.experience && <span className="error">{errors.experience}</span>}

          {/* Terms checkbox — FIX: original HTML had no id="terms" so getElementById failed */}
          <label style={{ display: 'flex', alignItems: 'center', gap: '8px', margin: '10px 0' }}>
            <input
              type="checkbox"
              style={{ width: 'auto' }}
              checked={formData.terms}
              onChange={e => update('terms', e.target.checked)}
            />
            I agree to terms.
          </label>
          {errors.terms && <span className="error">{errors.terms}</span>}

          <button type="submit" id="newcolor">Sign up for free</button>
        </form>
      </div>

      <div className="footer">
        <p>Email: krishanepadilla@gmail.com | &copy; All Rights Reserved 2026</p>
      </div>
    </main>
  );
}

export default RegisterPage;
